diff --git a/src/main/index.ts b/src/main/index.ts
index 9135ae9..138b472 100644
--- a/src/main/index.ts
+++ b/src/main/index.ts
@@ -578,10 +578,12 @@ function bootstrap(): void {
       // token 阶段1 临时生成 + 打日志(loopback 自测可见);safeStorage 持久化 +
       // 配对 UI 留阶段2(软件定义书 §14.9.4)。
       // 运行时 UI 启停服务会变端口/状态(controller.start/stop/setPort)。
-      // 订阅 controller 状态变化,同步托盘展示的端口(密码由 setDaemonToken 单独管)。
-      remoteDaemonController.onStatusChange = (s) => {
+      // 用 addStatusListener(不覆盖 ipc 的 broadcast 回调)同步托盘展示的端口。
+      // 历史教训:曾用 controller.onStatusChange = 赋值,覆盖了 ipc 设的 broadcast,
+      // 导致 start 后 UI 永远显示“未启动”(但 server 实际在跑)。
+      remoteDaemonController.addStatusListener((s) => {
         trayManager.setDaemonPort(s.running ? s.port : settingsManager.get().remoteDaemon.port);
-      };
+      });
       // v2.0 远程服务端:密码已加载(daemonCreds)。托盘菜单展示密码/端口 + 重置入口
       // (所有模式都有,不只 --daemon)。--daemon 命令行 / settings.autoStart → 自动启动。
       trayManager.setDaemonToken(currentDaemonToken);
diff --git a/src/main/remote-daemon-controller.ts b/src/main/remote-daemon-controller.ts
index 99decb6..940fe79 100644
--- a/src/main/remote-daemon-controller.ts
+++ b/src/main/remote-daemon-controller.ts
@@ -65,12 +65,31 @@ export class RemoteDaemonController {
   private remoteDaemon: RemoteDaemon | null = null;
   private currentPort: number | null = null;
   private listenCheck: { ok: boolean; reason?: string } | undefined = undefined;
+  /**
+   * 额外的状态监听器(index.ts 注入 tray 更新等)。onStatusChange 字段(ipc broadcast)
+   * 也会调,两者并存不覆盖 —— 历史教训:曾因 index 赋值 onStatusChange 覆盖了 ipc 的
+   * broadcast,导致 start 后 UI 永远不更新。
+   */
+  private statusListeners: Array<(status: DaemonStatus) => void> = [];
   /**
    * 状态广播器(index.ts 在 installIpcLayer 后赋值:接 ipc 的 broadcastEvent)。
    * 用 public 字段而非构造参数,避免 controller↔ipc 循环依赖。
+   * 注意:不要在外部再赋值覆盖它(会吞掉 broadcast);额外副作用用 addStatusListener。
    */
   onStatusChange: ((status: DaemonStatus) => void) | null = null;

+  /**
+   * 加一个状态监听器(不覆盖 onStatusChange)。index.ts 用它接 tray 端口同步等副作用。
+   * 返回取消订阅函数。
+   */
+  addStatusListener(fn: (status: DaemonStatus) => void): () => void {
+    this.statusListeners.push(fn);
+    return () => {
+      const i = this.statusListeners.indexOf(fn);
+      if (i >= 0) this.statusListeners.splice(i, 1);
+    };
+  }
+
   constructor(private readonly deps: RemoteDaemonControllerDeps) {}

   /**
@@ -207,6 +226,14 @@ export class RemoteDaemonController {
   }

   private emitStatus(): void {
-    this.onStatusChange?.(this.getStatus());
+    const status = this.getStatus();
+    this.onStatusChange?.(status);
+    for (const fn of this.statusListeners) {
+      try {
+        fn(status);
+      } catch {
+        /* 单个监听器出错不影响其他 */
+      }
+    }
   }
 }
